import React from 'react';
import { Router, Route, IndexRoute } from 'react-router';


import Main from './components/Main';
import About from './components/About';
import Work from './components/Work';
import Contact from './components/Contact';
import References from './components/References';
import Home from './components/Home';
import AhsanMemon from './components/AhsanMemon';
import SumairBaloch from './components/SumairBaloch';
import NajamLaghari from './components/NajamLaghari';

const Routes = (props) => (
  <Router {...props}>
    <Route path="/" component={Main} >
    <Route path='/about' component={About} />
    <Route path= "/work" component={Work} />
    <Route path= "/contact" component={Contact} />
    <Route path= "/references" component={References} />
    <Route path= "/ahsanmemon" component={AhsanMemon} />
    <Route path= "/sumairbaloch" component={SumairBaloch} />
	<Route path= "/najamlaghari" component={NajamLaghari} />
    	<IndexRoute component={Home}/>
    </Route>
  
  </Router>
);

export default Routes;



